  LoveApiSymbolDoc(
    symbol: "love.graphics.clear",
    module: "love.graphics",
    name: "clear",
    kind: "function",
    description:
        "Clears the screen or active Canvas to the specified color.\n\nThis function is called automatically before love.draw in the default love.run function. See the example in love.run for a typical use of this function.\n\nNote that the scissor area bounds the cleared region.\n\nIn versions prior to 11.0, color component values were within the range of 0 to 255 instead of 0 to 1.\n\nIn versions prior to background color instead.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[],
        returns: <LoveApiReturnDoc>[],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "r",
            type: "number",
            description: "The red channel of the color to clear the screen to.",
          ),
          LoveApiArgumentDoc(
            name: "g",
            type: "number",
            description:
                "The green channel of the color to clear the screen to.",
          ),
          LoveApiArgumentDoc(
            name: "b",
            type: "number",
            description:
                "The blue channel of the color to clear the screen to.",
          ),
          LoveApiArgumentDoc(
            name: "a",
            type: "number",
            description:
                "The alpha channel of the color to clear the screen to.",
            defaultValue: "1",
          ),
          LoveApiArgumentDoc(
            name: "clearstencil",
            type: "boolean",
            description:
                "Whether to clear the active stencil buffer, if present. It can also be an integer between 0 and 255 to clear the stencil buffer to a specific value.",
            defaultValue: "true",
          ),
          LoveApiArgumentDoc(
            name: "cleardepth",
            type: "boolean",
            description:
                "Whether to clear the active depth buffer, if present. It can also be a number between 0 and 1 to clear the depth buffer to a specific value.",
            defaultValue: "true",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "color",
            type: "table",
            description:
                "A table in the form of {r, g, b, a} containing the color to clear the first active Canvas to.",
          ),
          LoveApiArgumentDoc(
            name: "...",
            type: "table",
            description: "Additional tables for each active Canvas.",
          ),
          LoveApiArgumentDoc(
            name: "clearstencil",
            type: "boolean",
            description:
                "Whether to clear the active stencil buffer, if present. It can also be an integer between 0 and 255 to clear the stencil buffer to a specific value.",
            defaultValue: "true",
          ),
          LoveApiArgumentDoc(
            name: "cleardepth",
            type: "boolean",
            description:
                "Whether to clear the active depth buffer, if present. It can also be a number between 0 and 1 to clear the depth buffer to a specific value.",
            defaultValue: "true",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "clearcolor",
            type: "boolean",
            description:
                "Whether to clear the active color canvas to transparent black (0, 0, 0, 0). Typically this should be set to false with this variant of the function.",
          ),
          LoveApiArgumentDoc(
            name: "clearstencil",
            type: "boolean",
            description:
                "Whether to clear the active stencil buffer, if present. It can also be an integer between 0 and 255 to clear the stencil buffer to a specific value.",
          ),
          LoveApiArgumentDoc(
            name: "cleardepth",
