  LoveApiSymbolDoc(
    symbol: "love.graphics.discard",
    module: "love.graphics",
    name: "discard",
    kind: "function",
    description:
        "Discards (trashes) the contents of the screen or active Canvas. This is a performance optimization function with niche use cases.\n\nIf the active Canvas has just been changed and the 'replace' BlendMode is about to be used to draw something which covers the entire screen, calling love.graphics.discard rather than calling love.graphics.clear or doing nothing may improve performance on mobile devices.\n\nOn some desktop systems this function may do nothing.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "discardcolor",
            type: "boolean",
            description:
                "Whether to discard the texture(s) of the active Canvas(es) (the contents of the screen if no Canvas is active.)",
            defaultValue: "true",
          ),
          LoveApiArgumentDoc(
            name: "discardstencil",
            type: "boolean",
            description:
                "Whether to discard the contents of the stencil buffer of the screen / active Canvas.",
            defaultValue: "true",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "discardcolors",
            type: "table",
            description:
                "An array containing boolean values indicating whether to discard the texture of each active Canvas, when multiple simultaneous Canvases are active.",
          ),
          LoveApiArgumentDoc(
            name: "discardstencil",
            type: "boolean",
            description:
                "Whether to discard the contents of the stencil buffer of the screen / active Canvas.",
            defaultValue: "true",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/love.graphics.discard",
  ),
  LoveApiSymbolDoc(
    symbol: "love.graphics.draw",
    module: "love.graphics",
    name: "draw",
    kind: "function",
    description:
        "Draws a Drawable object (an Image, Canvas, SpriteBatch, ParticleSystem, Mesh, Text object, or Video) on the screen with optional rotation, scaling and shearing.\n\nObjects are drawn relative to their local coordinate system. The origin is by default located at the top left corner of Image and Canvas. All scaling, shearing, and rotation arguments transform the object relative to that point. Also, the position of the origin can be specified on the screen coordinate system.\n\nIt's possible to rotate an object about its center by offsetting the origin to the center. Angles must be given in radians for rotation. One can also use a negative scaling factor to flip about its centerline.\n\nNote that the offsets are applied before rotation, scaling, or shearing; scaling and shearing are applied before rotation.\n\nThe right and bottom edges of the object are shifted at an angle defined by the shearing factors.\n\nWhen using the default shader anything drawn with this function will be tinted according to the currently selected color.  Set it to pure white to preserve the object's original colors.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "drawable",
            type: "Drawable",
            description: "A drawable object.",
          ),
          LoveApiArgumentDoc(
            name: "x",
            type: "number",
            description: "The position to draw the object (x-axis).",
            defaultValue: "0",
          ),
          LoveApiArgumentDoc(
            name: "y",
            type: "number",
            description: "The position to draw the object (y-axis).",
            defaultValue: "0",
          ),
          LoveApiArgumentDoc(
            name: "r",
            type: "number",
            description: "Orientation (radians).",
            defaultValue: "0",
          ),
          LoveApiArgumentDoc(
            name: "sx",
            type: "number",
            description: "Scale factor (x-axis).",
            defaultValue: "1",
          ),
          LoveApiArgumentDoc(
            name: "sy",
            type: "number",
            description: "Scale factor (y-axis).",
            defaultValue: "sx",
          ),
          LoveApiArgumentDoc(
            name: "ox",
