  LoveApiSymbolDoc(
    symbol: "love.graphics.newArrayImage",
    module: "love.graphics",
    name: "newArrayImage",
    kind: "function",
    description:
        "Creates a new array Image.\n\nAn array image / array texture is a single object which contains multiple 'layers' or 'slices' of 2D sub-images. It can be thought of similarly to a texture atlas or sprite sheet, but it doesn't suffer from the same tile / quad bleeding artifacts that texture atlases do – although every sub-image must have the same dimensions.\n\nA specific layer of an array image can be drawn with love.graphics.drawLayer / SpriteBatch:addLayer, or with the Quad variant of love.graphics.draw and Quad:setLayer, or via a custom Shader.\n\nTo use an array image in a Shader, it must be declared as a ArrayImage or sampler2DArray type (instead of Image or sampler2D). The Texel(ArrayImage image, vec3 texturecoord) shader function must be used to get pixel colors from a slice of the array image. The vec3 argument contains the texture coordinate in the first two components, and the 0-based slice index in the third component.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "slices",
            type: "table",
            description:
                "A table containing filepaths to images (or File, FileData, ImageData, or CompressedImageData objects), in an array. Each sub-image must have the same dimensions. A table of tables can also be given, where each sub-table contains all mipmap levels for the slice index of that sub-table.",
          ),
          LoveApiArgumentDoc(
            name: "settings",
            type: "table",
            description:
                "Optional table of settings to configure the array image, containing the following fields:",
            defaultValue: "nil",
          ),
        ],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "image",
            type: "Image",
            description: "An Array Image object.",
          ),
        ],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/love.graphics.newArrayImage",
  ),
