  LoveApiSymbolDoc(
    symbol: "love.graphics.newQuad",
    module: "love.graphics",
    name: "newQuad",
    kind: "function",
    description:
        "Creates a new Quad.\n\nThe purpose of a Quad is to use a fraction of an image to draw objects, as opposed to drawing entire image. It is most useful for sprite sheets and atlases: in a sprite atlas, multiple sprites reside in same image, quad is used to draw a specific sprite from that image; in animated sprites with all frames residing in the same image, quad is used to draw specific frame from the animation.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "x",
            type: "number",
            description: "The top-left position in the Image along the x-axis.",
          ),
          LoveApiArgumentDoc(
            name: "y",
            type: "number",
            description: "The top-left position in the Image along the y-axis.",
          ),
          LoveApiArgumentDoc(
            name: "width",
            type: "number",
            description:
                "The width of the Quad in the Image. (Must be greater than 0.)",
          ),
          LoveApiArgumentDoc(
            name: "height",
