  LoveApiSymbolDoc(
    symbol: "love.graphics.newShader",
    module: "love.graphics",
    name: "newShader",
    kind: "function",
    description:
        "Creates a new Shader object for hardware-accelerated vertex and pixel effects. A Shader contains either vertex shader code, pixel shader code, or both.\n\nShaders are small programs which are run on the graphics card when drawing. Vertex shaders are run once for each vertex (for example, an image has 4 vertices - one at each corner. A Mesh might have many more.) Pixel shaders are run once for each pixel on the screen which the drawn object touches. Pixel shader code is executed after all the object's vertices have been processed by the vertex shader.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "code",
            type: "string",
            description:
                "The pixel shader or vertex shader code, or a filename pointing to a file with the code.",
          ),
        ],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "shader",
            type: "Shader",
            description: "A Shader object for use in drawing operations.",
          ),
        ],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "pixelcode",
            type: "string",
            description:
                "The pixel shader code, or a filename pointing to a file with the code.",
          ),
          LoveApiArgumentDoc(
            name: "vertexcode",
            type: "string",
            description:
                "The vertex shader code, or a filename pointing to a file with the code.",
          ),
        ],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "shader",
            type: "Shader",
            description: "A Shader object for use in drawing operations.",
          ),
        ],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/love.graphics.newShader",
  ),
