  LoveApiSymbolDoc(
    symbol: "love.graphics.printf",
    module: "love.graphics",
    name: "printf",
    kind: "function",
    description:
        "Draws formatted text, with word wrap and alignment.\n\nSee additional notes in love.graphics.print.\n\nThe word wrap limit is applied before any scaling, rotation, and other coordinate transformations. Therefore the amount of text per line stays constant given the same wrap limit, even if the scale arguments change.\n\nIn version 0.9.2 and earlier, wrapping was implemented by breaking up words by spaces and putting them back together to make sure things fit nicely within the limit provided. However, due to the way this is done, extra spaces between words would end up missing when printed on the screen, and some lines could overflow past the provided wrap limit. In version 0.10.0 and newer this is no longer the case.\n\nIn versions prior to 11.0, color and byte component values were within the range of 0 to 255 instead of 0 to 1.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "text",
            type: "string",
            description: "A text string.",
          ),
          LoveApiArgumentDoc(
            name: "x",
            type: "number",
            description: "The position on the x-axis.",
          ),
          LoveApiArgumentDoc(
            name: "y",
            type: "number",
            description: "The position on the y-axis.",
          ),
          LoveApiArgumentDoc(
            name: "limit",
            type: "number",
            description: "Wrap the line after this many horizontal pixels.",
          ),
          LoveApiArgumentDoc(
            name: "align",
            type: "AlignMode",
            description: "The alignment.",
            defaultValue: "'left'",
          ),
          LoveApiArgumentDoc(
            name: "r",
            type: "number",
            description: "Orientation (radians).",
            defaultValue: "0",
          ),
          LoveApiArgumentDoc(
            name: "sx",
            type: "number",
            description: "Scale factor (x-axis).",
            defaultValue: "1",
          ),
          LoveApiArgumentDoc(
            name: "sy",
            type: "number",
            description: "Scale factor (y-axis).",
            defaultValue: "sx",
          ),
          LoveApiArgumentDoc(
            name: "ox",
            type: "number",
            description: "Origin offset (x-axis).",
