  LoveApiSymbolDoc(
    symbol: "love.graphics.rotate",
    module: "love.graphics",
    name: "rotate",
    kind: "function",
    description:
        "Rotates the coordinate system in two dimensions.\n\nCalling this function affects all future drawing operations by rotating the coordinate system around the origin by the given amount of radians. This change lasts until love.draw() exits.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "angle",
            type: "number",
            description:
                "The amount to rotate the coordinate system in radians.",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/love.graphics.rotate",
  ),
  LoveApiSymbolDoc(
    symbol: "love.graphics.scale",
    module: "love.graphics",
    name: "scale",
    kind: "function",
    description:
        "Scales the coordinate system in two dimensions.\n\nBy default the coordinate system in LÖVE corresponds to the display pixels in horizontal and vertical directions one-to-one, and the x-axis increases towards the right while the y-axis increases downwards. Scaling the coordinate system changes this relation.\n\nAfter scaling by sx and sy, all coordinates are treated as if they were multiplied by sx and sy. Every result of a drawing operation is also correspondingly scaled, so scaling by (2, 2) for example would mean making everything twice as large in both x- and y-directions. Scaling by a negative value flips the coordinate system in the corresponding direction, which also means everything will be drawn flipped or upside down, or both. Scaling by zero is not a useful operation.\n\nScale and translate are not commutative operations, therefore, calling them in different orders will change the outcome.\n\nScaling lasts until love.draw() exits.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "sx",
            type: "number",
            description: "The scaling in the direction of the x-axis.",
          ),
          LoveApiArgumentDoc(
            name: "sy",
            type: "number",
            description:
                "The scaling in the direction of the y-axis. If omitted, it defaults to same as parameter sx.",
            defaultValue: "sx",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/love.graphics.scale",
  ),
