  LoveApiSymbolDoc(
    symbol: "love.graphics.stencil",
    module: "love.graphics",
    name: "stencil",
    kind: "function",
    description:
        "Draws geometry as a stencil.\n\nThe geometry drawn by the supplied function sets invisible stencil values of pixels, instead of setting pixel colors. The stencil buffer (which contains those stencil values) can act like a mask / stencil - love.graphics.setStencilTest can be used afterward to determine how further rendering is affected by the stencil values in each pixel.\n\nStencil values are integers within the range of 255.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "stencilfunction",
            type: "function",
            description:
                "Function which draws geometry. The stencil values of pixels, rather than the color of each pixel, will be affected by the geometry.",
          ),
          LoveApiArgumentDoc(
            name: "action",
            type: "StencilAction",
            description:
                "How to modify any stencil values of pixels that are touched by what's drawn in the stencil function.",
            defaultValue: "'replace'",
          ),
          LoveApiArgumentDoc(
            name: "value",
            type: "number",
            description:
                "The new stencil value to use for pixels if the 'replace' stencil action is used. Has no effect with other stencil actions. Must be between 0 and 255.",
            defaultValue: "1",
          ),
          LoveApiArgumentDoc(
            name: "keepvalues",
            type: "boolean",
            description:
                "True to preserve old stencil values of pixels, false to re-set every pixel's stencil value to 0 before executing the stencil function. love.graphics.clear will also re-set all stencil values.",
            defaultValue: "false",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/love.graphics.stencil",
  ),
