  LoveApiSymbolDoc(
    symbol: "ParticleSystem:setColors",
    module: "love.graphics",
    name: "setColors",
    kind: "method",
    description:
        "Sets a series of colors to apply to the particle sprite. The particle system will interpolate between each color evenly over the particle's lifetime.\n\nArguments can be passed in groups of four, representing the components of the desired RGBA value, or as tables of RGBA component values, with a default alpha value of 1 if only three values are given. At least one color must be specified. A maximum of eight may be used.\n\nIn versions prior to 11.0, color component values were within the range of 0 to 255 instead of 0 to 1.",
    container: "ParticleSystem",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "r1",
            type: "number",
            description: "First color, red component (0-1).",
          ),
          LoveApiArgumentDoc(
            name: "g1",
            type: "number",
            description: "First color, green component (0-1).",
          ),
          LoveApiArgumentDoc(
            name: "b1",
            type: "number",
            description: "First color, blue component (0-1).",
          ),
          LoveApiArgumentDoc(
            name: "a1",
            type: "number",
            description: "First color, alpha component (0-1).",
            defaultValue: "1",
          ),
          LoveApiArgumentDoc(
            name: "...",
            type: "number",
            description: "Additional colors.",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "rgba1",
            type: "table",
            description:
                "First color, a numerical indexed table with the red, green, blue and alpha values as numbers (0-1). The alpha is optional and defaults to 1 if it is left out.",
          ),
          LoveApiArgumentDoc(
            name: "...",
            type: "table",
            description:
                "Additional color, a numerical indexed table with the red, green, blue and alpha values as numbers (0-1). The alpha is optional and defaults to 1 if it is left out.",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/ParticleSystem:setColors",
  ),
