  ),
  LoveApiSymbolDoc(
    symbol: "Shader:send",
    module: "love.graphics",
    name: "send",
    kind: "method",
    description:
        "Sends one or more values to a special (''uniform'') variable inside the shader. Uniform variables have to be marked using the ''uniform'' or ''extern'' keyword, e.g.\n\nuniform float time;  // 'float' is the typical number type used in GLSL shaders.\n\nuniform float varsvec2 light_pos;\n\nuniform vec4 colors[4;\n\nThe corresponding send calls would be\n\nshader:send('time', t)\n\nshader:send('vars',a,b)\n\nshader:send('light_pos', {light_x, light_y})\n\nshader:send('colors', {r1, g1, b1, a1},  {r2, g2, b2, a2},  {r3, g3, b3, a3},  {r4, g4, b4, a4})\n\nUniform / extern variables are read-only in the shader code and remain constant until modified by a Shader:send call. Uniform variables can be accessed in both the Vertex and Pixel components of a shader, as long as the variable is declared in each.",
    container: "Shader",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "name",
            type: "string",
            description: "Name of the number to send to the shader.",
          ),
          LoveApiArgumentDoc(
            name: "number",
            type: "number",
            description: "Number to send to store in the uniform variable.",
          ),
          LoveApiArgumentDoc(
            name: "...",
            type: "number",
            description:
                "Additional numbers to send if the uniform variable is an array.",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "name",
            type: "string",
            description: "Name of the vector to send to the shader.",
          ),
          LoveApiArgumentDoc(
            name: "vector",
            type: "table",
            description:
                "Numbers to send to the uniform variable as a vector. The number of elements in the table determines the type of the vector (e.g. two numbers -&gt; vec2). At least two and at most four numbers can be used.",
          ),
          LoveApiArgumentDoc(
            name: "...",
            type: "table",
            description:
                "Additional vectors to send if the uniform variable is an array. All vectors need to be of the same size (e.g. only vec3's).",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "name",
            type: "string",
            description: "Name of the matrix to send to the shader.",
          ),
          LoveApiArgumentDoc(
            name: "matrix",
            type: "table",
            description:
                "2x2, 3x3, or 4x4 matrix to send to the uniform variable. Using table form: {{a,b,c,d}, {e,f,g,h}, ... } or (since version 0.10.2) {a,b,c,d, e,f,g,h, ...}. The order in 0.10.2 is column-major; starting in 11.0 it's row-major instead.",
          ),
          LoveApiArgumentDoc(
            name: "...",
            type: "table",
            description:
                "Additional matrices of the same type as ''matrix'' to store in a uniform array.",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "name",
            type: "string",
            description: "Name of the Texture to send to the shader.",
          ),
          LoveApiArgumentDoc(
            name: "texture",
            type: "Texture",
            description:
                "Texture (Image or Canvas) to send to the uniform variable.",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "name",
            type: "string",
            description: "Name of the boolean to send to the shader.",
          ),
          LoveApiArgumentDoc(
            name: "boolean",
            type: "boolean",
            description: "Boolean to send to store in the uniform variable.",
          ),
          LoveApiArgumentDoc(
            name: "...",
            type: "boolean",
            description:
                "Additional booleans to send if the uniform variable is an array.",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "name",
            type: "string",
            description: "Name of the matrix to send to the shader.",
          ),
          LoveApiArgumentDoc(
            name: "matrixlayout",
            type: "MatrixLayout",
            description: "The layout (row- or column-major) of the matrix.",
          ),
          LoveApiArgumentDoc(
            name: "matrix",
            type: "table",
            description:
                "2x2, 3x3, or 4x4 matrix to send to the uniform variable. Using table form: {{a,b,c,d}, {e,f,g,h}, ... } or {a,b,c,d, e,f,g,h, ...}.",
          ),
          LoveApiArgumentDoc(
            name: "...",
            type: "table",
            description:
                "Additional matrices of the same type as ''matrix'' to store in a uniform array.",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "name",
            type: "string",
            description: "Name of the uniform to send to the shader.",
          ),
          LoveApiArgumentDoc(
            name: "data",
            type: "Data",
