  LoveApiSymbolDoc(
    symbol: "Shader:sendColor",
    module: "love.graphics",
    name: "sendColor",
    kind: "method",
    description:
        "Sends one or more colors to a special (''extern'' / ''uniform'') vec3 or vec4 variable inside the shader. The color components must be in the range of 1. The colors are gamma-corrected if global gamma-correction is enabled.\n\nExtern variables must be marked using the ''extern'' keyword, e.g.\n\nextern vec4 Color;\n\nThe corresponding sendColor call would be\n\nshader:sendColor('Color', {r, g, b, a})\n\nExtern variables can be accessed in both the Vertex and Pixel stages of a shader, as long as the variable is declared in each.\n\nIn versions prior to 11.0, color component values were within the range of 0 to 255 instead of 0 to 1.",
    container: "Shader",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "name",
            type: "string",
            description:
                "The name of the color extern variable to send to in the shader.",
          ),
          LoveApiArgumentDoc(
            name: "color",
            type: "table",
            description:
                "A table with red, green, blue, and optional alpha color components in the range of 1 to send to the extern as a vector.",
          ),
          LoveApiArgumentDoc(
            name: "...",
            type: "table",
            description:
                "Additional colors to send in case the extern is an array. All colors need to be of the same size (e.g. only vec3's).",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/Shader:sendColor",
  ),
