  LoveApiSymbolDoc(
    symbol: "Texture:getDPIScale",
    module: "love.graphics",
    name: "getDPIScale",
    kind: "method",
    description:
        "Gets the DPI scale factor of the Texture.\n\nThe DPI scale factor represents relative pixel density. A DPI scale factor of 2 means the texture has twice the pixel density in each dimension (4 times as many pixels in the same area) compared to a texture with a DPI scale factor of 1.\n\nFor example, a texture with pixel dimensions of 100x100 with a DPI scale factor of 2 will be drawn as if it was 50x50. This is useful with high-dpi /  retina displays to easily allow swapping out higher or lower pixel density Images and Canvases without needing any extra manual scaling logic.",
    container: "Texture",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "dpiscale",
            type: "number",
            description: "The DPI scale factor of the Texture.",
          ),
        ],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/Texture:getDPIScale",
  ),
