  LoveApiSymbolDoc(
    symbol: "Texture:setDepthSampleMode",
    module: "love.graphics",
    name: "setDepthSampleMode",
    kind: "method",
    description:
        "Sets the comparison mode used when sampling from a depth texture in a shader. Depth texture comparison modes are advanced low-level functionality typically used with shadow mapping in 3D.\n\nWhen using a depth texture with a comparison mode set in a shader, it must be declared as a sampler2DShadow and used in a GLSL 3 Shader. The result of accessing the texture in the shader will return a float between 0 and 1, proportional to the number of samples (up to 4 samples will be used if bilinear filtering is enabled) that passed the test set by the comparison operation.\n\nDepth texture comparison can only be used with readable depth-formatted Canvases.",
    container: "Texture",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "compare",
            type: "CompareMode",
            description:
                "The comparison mode used when sampling from this texture in a shader.",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/Texture:setDepthSampleMode",
  ),
  LoveApiSymbolDoc(
    symbol: "Texture:setFilter",
    module: "love.graphics",
    name: "setFilter",
    kind: "method",
    description: "Sets the filter mode of the Texture.",
    container: "Texture",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "min",
            type: "FilterMode",
            description:
                "Filter mode to use when minifying the texture (rendering it at a smaller size on-screen than its size in pixels).",
          ),
          LoveApiArgumentDoc(
            name: "mag",
            type: "FilterMode",
            description:
                "Filter mode to use when magnifying the texture (rendering it at a larger size on-screen than its size in pixels).",
            defaultValue: "min",
          ),
          LoveApiArgumentDoc(
            name: "anisotropy",
            type: "number",
            description: "Maximum amount of anisotropic filtering to use.",
            defaultValue: "1",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
