  ),
  LoveApiSymbolDoc(
    symbol: "Texture:setMipmapFilter",
    module: "love.graphics",
    name: "setMipmapFilter",
    kind: "method",
    description:
        "Sets the mipmap filter mode for a Texture. Prior to 11.0 this method only worked on Images.\n\nMipmapping is useful when drawing a texture at a reduced scale. It can improve performance and reduce aliasing issues.\n\nIn created with the mipmaps flag enabled for the mipmap filter to have any effect. In versions prior to 0.10.0 it's best to call this method directly after creating the image with love.graphics.newImage, to avoid bugs in certain graphics drivers.\n\nDue to hardware restrictions and driver bugs, in versions prior to 0.10.0 images that weren't loaded from a CompressedData must have power-of-two dimensions (64x64, 512x256, etc.) to use mipmaps.",
    container: "Texture",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "filtermode",
            type: "FilterMode",
            description:
                "The filter mode to use in between mipmap levels. 'nearest' will often give better performance.",
          ),
          LoveApiArgumentDoc(
            name: "sharpness",
            type: "number",
            description:
                "A positive sharpness value makes the texture use a more detailed mipmap level when drawing, at the expense of performance. A negative value does the reverse.",
            defaultValue: "0",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[],
        returns: <LoveApiReturnDoc>[],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/Texture:setMipmapFilter",
  ),
  LoveApiSymbolDoc(
    symbol: "Texture:setWrap",
    module: "love.graphics",
    name: "setWrap",
    kind: "method",
    description:
        "Sets the wrapping properties of a Texture.\n\nThis function sets the way a Texture is repeated when it is drawn with a Quad that is larger than the texture's extent, or when a custom Shader is used which uses texture coordinates outside of [0, 1]. A texture may be clamped or set to repeat in both horizontal and vertical directions.\n\nClamped textures appear only once (with the edges of the texture stretching to fill the extent of the Quad), whereas repeated ones repeat as many times as there is room in the Quad.",
    container: "Texture",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "horiz",
            type: "WrapMode",
            description: "Horizontal wrapping mode of the texture.",
          ),
          LoveApiArgumentDoc(
            name: "vert",
            type: "WrapMode",
            description: "Vertical wrapping mode of the texture.",
            defaultValue: "horiz",
          ),
          LoveApiArgumentDoc(
            name: "depth",
            type: "WrapMode",
            description: "Wrapping mode for the z-axis of a Volume texture.",
            defaultValue: "horiz",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/Texture:setWrap",
  ),
