  LoveApiSymbolDoc(
    symbol: "ImageData:mapPixel",
    module: "love.image",
    name: "mapPixel",
    kind: "method",
    description:
        "Transform an image by applying a function to every pixel.\n\nThis function is a higher-order function. It takes another function as a parameter, and calls it once for each pixel in the ImageData.\n\nThe passed function is called with six parameters for each pixel in turn. The parameters are numbers that represent the x and y coordinates of the pixel and its red, green, blue and alpha values. The function should return the new red, green, blue, and alpha values for that pixel.\n\nfunction pixelFunction(x, y, r, g, b, a)\n\n-- template for defining your own pixel mapping function\n\n-- perform computations giving the new values for r, g, b and a\n\n-- ...\n\nreturn r, g, b, a\n\nend\n\nIn versions prior to 11.0, color component values were within the range of 0 to 255 instead of 0 to 1.",
    container: "ImageData",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "pixelFunction",
            type: "function",
            description: "Function to apply to every pixel.",
          ),
          LoveApiArgumentDoc(
            name: "x",
            type: "number",
            description:
                "The x-axis of the top-left corner of the area within the ImageData to apply the function to.",
            defaultValue: "0",
          ),
          LoveApiArgumentDoc(
            name: "y",
            type: "number",
            description:
                "The y-axis of the top-left corner of the area within the ImageData to apply the function to.",
            defaultValue: "0",
          ),
          LoveApiArgumentDoc(
            name: "width",
            type: "number",
            description:
                "The width of the area within the ImageData to apply the function to.",
            defaultValue: "ImageData:getWidth()",
          ),
          LoveApiArgumentDoc(
            name: "height",
            type: "number",
            description:
                "The height of the area within the ImageData to apply the function to.",
            defaultValue: "ImageData:getHeight()",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/ImageData:mapPixel",
  ),
