  LoveApiSymbolDoc(
    symbol: "love.joystick.setGamepadMapping",
    module: "love.joystick",
    name: "setGamepadMapping",
    kind: "function",
    description:
        "Binds a virtual gamepad input to a button, axis or hat for all Joysticks of a certain type. For example, if this function is used with a GUID returned by a Dualshock 3 controller in OS X, the binding will affect Joystick:getGamepadAxis and Joystick:isGamepadDown for ''all'' Dualshock 3 controllers used with the game when run in OS X.\n\nLÖVE includes built-in gamepad bindings for many common controllers. This function lets you change the bindings or add new ones for types of Joysticks which aren't recognized as gamepads by default.\n\nThe virtual gamepad buttons and axes are designed around the Xbox 360 controller layout.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "guid",
            type: "string",
            description:
                "The OS-dependent GUID for the type of Joystick the binding will affect.",
          ),
          LoveApiArgumentDoc(
            name: "button",
            type: "GamepadButton",
            description: "The virtual gamepad button to bind.",
          ),
          LoveApiArgumentDoc(
            name: "inputtype",
            type: "JoystickInputType",
            description:
                "The type of input to bind the virtual gamepad button to.",
          ),
          LoveApiArgumentDoc(
            name: "inputindex",
            type: "number",
            description:
                "The index of the axis, button, or hat to bind the virtual gamepad button to.",
          ),
          LoveApiArgumentDoc(
            name: "hatdir",
            type: "JoystickHat",
            description:
                "The direction of the hat, if the virtual gamepad button will be bound to a hat. nil otherwise.",
            defaultValue: "nil",
          ),
        ],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "success",
            type: "boolean",
            description:
                "Whether the virtual gamepad button was successfully bound.",
          ),
        ],
      ),
