  LoveApiSymbolDoc(
    symbol: "love.math.linearToGamma",
    module: "love.math",
    name: "linearToGamma",
    kind: "function",
    description:
        "Converts a color from linear-space (RGB) to gamma-space (sRGB). This is useful when storing linear RGB color values in an image, because the linear RGB color space has less precision than sRGB for dark colors, which can result in noticeable color banding when drawing.\n\nIn general, colors chosen based on what they look like on-screen are already in gamma-space and should not be double-converted. Colors calculated using math are often in the linear RGB space.\n\nRead more about gamma-correct rendering here, here, and here.\n\nIn versions prior to 11.0, color component values were within the range of 0 to 255 instead of 0 to 1.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "lr",
            type: "number",
            description: "The red channel of the linear RGB color to convert.",
          ),
          LoveApiArgumentDoc(
            name: "lg",
            type: "number",
            description:
                "The green channel of the linear RGB color to convert.",
          ),
          LoveApiArgumentDoc(
            name: "lb",
            type: "number",
            description: "The blue channel of the linear RGB color to convert.",
          ),
        ],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "cr",
            type: "number",
            description:
                "The red channel of the converted color in gamma sRGB space.",
          ),
          LoveApiReturnDoc(
            name: "cg",
            type: "number",
            description:
                "The green channel of the converted color in gamma sRGB space.",
          ),
          LoveApiReturnDoc(
            name: "cb",
            type: "number",
            description:
                "The blue channel of the converted color in gamma sRGB space.",
          ),
        ],
      ),
      LoveApiVariantDoc(
