  LoveApiSymbolDoc(
    symbol: "love.mouse.newCursor",
    module: "love.mouse",
    name: "newCursor",
    kind: "function",
    description:
        "Creates a new hardware Cursor object from an image file or ImageData.\n\nHardware cursors are framerate-independent and work the same way as normal operating system cursors. Unlike drawing an image at the mouse's current coordinates, hardware cursors never have visible lag between when the mouse is moved and when the cursor position updates, even at low framerates.\n\nThe hot spot is the point the operating system uses to determine what was clicked and at what position the mouse cursor is. For example, the normal arrow pointer normally has its hot spot at the top left of the image, but a crosshair cursor might have it in the middle.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "imageData",
            type: "ImageData",
            description: "The ImageData to use for the new Cursor.",
          ),
          LoveApiArgumentDoc(
            name: "hotx",
            type: "number",
            description:
                "The x-coordinate in the ImageData of the cursor's hot spot.",
            defaultValue: "0",
          ),
          LoveApiArgumentDoc(
            name: "hoty",
            type: "number",
            description:
                "The y-coordinate in the ImageData of the cursor's hot spot.",
            defaultValue: "0",
          ),
        ],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "cursor",
            type: "Cursor",
            description: "The new Cursor object.",
          ),
        ],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "filename",
            type: "string",
            description: "Path to the image to use for the new Cursor.",
