          LoveApiArgumentDoc(
            name: "hotx",
            type: "number",
            description:
                "The x-coordinate in the image of the cursor's hot spot.",
            defaultValue: "0",
          ),
          LoveApiArgumentDoc(
            name: "hoty",
            type: "number",
            description:
                "The y-coordinate in the image of the cursor's hot spot.",
            defaultValue: "0",
          ),
        ],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
