  LoveApiSymbolDoc(
    symbol: "love.physics.newBody",
    module: "love.physics",
    name: "newBody",
    kind: "function",
    description:
        "Creates a new body.\n\nThere are three types of bodies.\n\n* Static bodies do not move, have a infinite mass, and can be used for level boundaries.\n\n* Dynamic bodies are the main actors in the simulation, they collide with everything.\n\n* Kinematic bodies do not react to forces and only collide with dynamic bodies.\n\nThe mass of the body gets calculated when a Fixture is attached or removed, but can be changed at any time with Body:setMass or Body:resetMassData.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "world",
            type: "World",
            description: "The world to create the body in.",
          ),
          LoveApiArgumentDoc(
            name: "x",
            type: "number",
            description: "The x position of the body.",
            defaultValue: "0",
          ),
          LoveApiArgumentDoc(
            name: "y",
            type: "number",
            description: "The y position of the body.",
            defaultValue: "0",
          ),
          LoveApiArgumentDoc(
            name: "type",
            type: "BodyType",
            description: "The type of the body.",
            defaultValue: "'static'",
          ),
        ],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "body",
            type: "Body",
            description: "A new body.",
          ),
        ],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/love.physics.newBody",
  ),
