  LoveApiSymbolDoc(
    symbol: "love.physics.setMeter",
    module: "love.physics",
    name: "setMeter",
    kind: "function",
    description:
        "Sets the pixels to meter scale factor.\n\nAll coordinates in the physics module are divided by this number and converted to meters, and it creates a convenient way to draw the objects directly to the screen without the need for graphics transformations.\n\nIt is recommended to create shapes no larger than 10 times the scale. This is important because Box2D is tuned to work well with shape sizes from 0.1 to 10 meters. The default meter scale is 30.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "scale",
            type: "number",
            description: "The scale factor as an integer.",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/love.physics.setMeter",
  ),
  LoveApiSymbolDoc(
    symbol: "Body:applyAngularImpulse",
    module: "love.physics",
    name: "applyAngularImpulse",
    kind: "method",
    description:
        "Applies an angular impulse to a body. This makes a single, instantaneous addition to the body momentum.\n\nA body with with a larger mass will react less. The reaction does '''not''' depend on the timestep, and is equivalent to applying a force continuously for 1 second. Impulses are best used to give a single push to a body. For a continuous push to a body it is better to use Body:applyForce.",
    container: "Body",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "impulse",
            type: "number",
            description: "The impulse in kilogram-square meter per second.",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/Body:applyAngularImpulse",
  ),
  LoveApiSymbolDoc(
    symbol: "Body:applyForce",
    module: "love.physics",
    name: "applyForce",
    kind: "method",
    description:
        "Apply force to a Body.\n\nA force pushes a body in a direction. A body with with a larger mass will react less. The reaction also depends on how long a force is applied: since the force acts continuously over the entire timestep, a short timestep will only push the body for a short time. Thus forces are best used for many timesteps to give a continuous push to a body (like gravity). For a single push that is independent of timestep, it is better to use Body:applyLinearImpulse.\n\nIf the position to apply the force is not given, it will act on the center of mass of the body. The part of the force not directed towards the center of mass will cause the body to spin (and depends on the rotational inertia).\n\nNote that the force components and position must be given in world coordinates.",
    container: "Body",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "fx",
            type: "number",
            description:
                "The x component of force to apply to the center of mass.",
          ),
          LoveApiArgumentDoc(
            name: "fy",
            type: "number",
            description:
                "The y component of force to apply to the center of mass.",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "fx",
            type: "number",
            description: "The x component of force to apply.",
          ),
          LoveApiArgumentDoc(
            name: "fy",
            type: "number",
            description: "The y component of force to apply.",
          ),
          LoveApiArgumentDoc(
            name: "x",
            type: "number",
            description: "The x position to apply the force.",
          ),
          LoveApiArgumentDoc(
            name: "y",
            type: "number",
            description: "The y position to apply the force.",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/Body:applyForce",
  ),
  LoveApiSymbolDoc(
    symbol: "Body:applyLinearImpulse",
    module: "love.physics",
    name: "applyLinearImpulse",
    kind: "method",
    description:
        "Applies an impulse to a body.\n\nThis makes a single, instantaneous addition to the body momentum.\n\nAn impulse pushes a body in a direction. A body with with a larger mass will react less. The reaction does '''not''' depend on the timestep, and is equivalent to applying a force continuously for 1 second. Impulses are best used to give a single push to a body. For a continuous push to a body it is better to use Body:applyForce.\n\nIf the position to apply the impulse is not given, it will act on the center of mass of the body. The part of the impulse not directed towards the center of mass will cause the body to spin (and depends on the rotational inertia).\n\nNote that the impulse components and position must be given in world coordinates.",
    container: "Body",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "ix",
            type: "number",
            description:
                "The x component of the impulse applied to the center of mass.",
          ),
          LoveApiArgumentDoc(
            name: "iy",
            type: "number",
            description:
                "The y component of the impulse applied to the center of mass.",
