            description: "The y component of the impulse.",
          ),
          LoveApiArgumentDoc(
            name: "x",
            type: "number",
            description: "The x position to apply the impulse.",
          ),
          LoveApiArgumentDoc(
            name: "y",
            type: "number",
            description: "The y position to apply the impulse.",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/Body:applyLinearImpulse",
  ),
