  LoveApiSymbolDoc(
    symbol: "Body:getAngle",
    module: "love.physics",
    name: "getAngle",
    kind: "method",
    description:
        "Get the angle of the body.\n\nThe angle is measured in radians. If you need to transform it to degrees, use math.deg.\n\nA value of 0 radians will mean 'looking to the right'. Although radians increase counter-clockwise, the y axis points down so it becomes ''clockwise'' from our point of view.",
    container: "Body",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "angle",
            type: "number",
            description: "The angle in radians.",
          ),
