    ],
    wikiPath: "https://www.love2d.org/wiki/Body:getAngle",
  ),
  LoveApiSymbolDoc(
    symbol: "Body:getAngularDamping",
    module: "love.physics",
    name: "getAngularDamping",
    kind: "method",
    description:
        "Gets the Angular damping of the Body\n\nThe angular damping is the ''rate of decrease of the angular velocity over time'': A spinning body with no damping and no external forces will continue spinning indefinitely. A spinning body with damping will gradually stop spinning.\n\nDamping is not the same as friction - they can be modelled together. However, only damping is provided by Box2D (and LOVE).\n\nDamping parameters should be between 0 and infinity, with 0 meaning no damping, and infinity meaning full damping. Normally you will use a damping value between 0 and 0.1.",
    container: "Body",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "damping",
            type: "number",
            description: "The value of the angular damping.",
          ),
        ],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/Body:getAngularDamping",
  ),
  LoveApiSymbolDoc(
    symbol: "Body:getAngularVelocity",
    module: "love.physics",
    name: "getAngularVelocity",
    kind: "method",
    description:
        "Get the angular velocity of the Body.\n\nThe angular velocity is the ''rate of change of angle over time''.\n\nIt is changed in World:update by applying torques, off centre forces/impulses, and angular damping. It can be set directly with Body:setAngularVelocity.\n\nIf you need the ''rate of change of position over time'', use Body:getLinearVelocity.",
    container: "Body",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "w",
            type: "number",
            description: "The angular velocity in radians/second.",
          ),
        ],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/Body:getAngularVelocity",
  ),
