  LoveApiSymbolDoc(
    symbol: "Body:getLinearVelocity",
    module: "love.physics",
    name: "getLinearVelocity",
    kind: "method",
    description:
        "Gets the linear velocity of the Body from its center of mass.\n\nThe linear velocity is the ''rate of change of position over time''.\n\nIf you need the ''rate of change of angle over time'', use Body:getAngularVelocity.\n\nIf you need to get the linear velocity of a point different from the center of mass:\n\n*  Body:getLinearVelocityFromLocalPoint allows you to specify the point in local coordinates.\n\n*  Body:getLinearVelocityFromWorldPoint allows you to specify the point in world coordinates.\n\nSee page 136 of 'Essential Mathematics for Games and Interactive Applications' for definitions of local and world coordinates.",
    container: "Body",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "x",
            type: "number",
            description: "The x-component of the velocity vector",
          ),
          LoveApiReturnDoc(
            name: "y",
            type: "number",
            description: "The y-component of the velocity vector",
          ),
        ],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/Body:getLinearVelocity",
  ),
  LoveApiSymbolDoc(
    symbol: "Body:getLinearVelocityFromLocalPoint",
    module: "love.physics",
    name: "getLinearVelocityFromLocalPoint",
    kind: "method",
    description:
        "Get the linear velocity of a point on the body.\n\nThe linear velocity for a point on the body is the velocity of the body center of mass plus the velocity at that point from the body spinning.\n\nThe point on the body must given in local coordinates. Use Body:getLinearVelocityFromWorldPoint to specify this with world coordinates.",
    container: "Body",
