  LoveApiSymbolDoc(
    symbol: "Fixture:rayCast",
    module: "love.physics",
    name: "rayCast",
    kind: "method",
    description:
        "Casts a ray against the shape of the fixture and returns the surface normal vector and the line position where the ray hit. If the ray missed the shape, nil will be returned.\n\nThe ray starts on the first point of the input line and goes towards the second point of the line. The fifth argument is the maximum distance the ray is going to travel as a scale factor of the input line length.\n\nThe childIndex parameter is used to specify which child of a parent shape, such as a ChainShape, will be ray casted. For ChainShapes, the index of 1 is the first edge on the chain. Ray casting a parent shape will only test the child specified so if you want to test every shape of the parent, you must loop through all of its children.\n\nThe world position of the impact can be calculated by multiplying the line vector with the third return value and adding it to the line starting point.\n\nhitx, hity = x1 + (x2 - x1) * fraction, y1 + (y2 - y1) * fraction",
    container: "Fixture",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "x1",
            type: "number",
            description: "The x position of the input line starting point.",
          ),
          LoveApiArgumentDoc(
            name: "y1",
            type: "number",
            description: "The y position of the input line starting point.",
          ),
          LoveApiArgumentDoc(
            name: "x2",
            type: "number",
            description: "The x position of the input line end point.",
          ),
          LoveApiArgumentDoc(
            name: "y2",
            type: "number",
            description: "The y position of the input line end point.",
          ),
          LoveApiArgumentDoc(
            name: "maxFraction",
            type: "number",
            description: "Ray length parameter.",
          ),
          LoveApiArgumentDoc(
            name: "childIndex",
            type: "number",
            description: "The index of the child the ray gets cast against.",
            defaultValue: "1",
          ),
        ],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "xn",
            type: "number",
            description:
                "The x component of the normal vector of the edge where the ray hit the shape.",
          ),
          LoveApiReturnDoc(
            name: "yn",
            type: "number",
            description:
                "The y component of the normal vector of the edge where the ray hit the shape.",
          ),
          LoveApiReturnDoc(
            name: "fraction",
            type: "number",
            description:
                "The position on the input line where the intersection happened as a factor of the line length.",
          ),
        ],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/Fixture:rayCast",
  ),
