  LoveApiSymbolDoc(
    symbol: "World:setCallbacks",
    module: "love.physics",
    name: "setCallbacks",
    kind: "method",
    description:
        "Sets functions for the collision callbacks during the world update.\n\nFour Lua functions can be given as arguments. The value nil removes a function.\n\nWhen called, each function will be passed three arguments. The first two arguments are the colliding fixtures and the third argument is the Contact between them. The postSolve callback additionally gets the normal and tangent impulse for each contact point. See notes.\n\nIf you are interested to know when exactly each callback is called, consult a Box2d manual",
    container: "World",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "beginContact",
            type: "function",
            description: "Gets called when two fixtures begin to overlap.",
          ),
          LoveApiArgumentDoc(
            name: "endContact",
            type: "function",
            description:
                "Gets called when two fixtures cease to overlap. This will also be called outside of a world update, when colliding objects are destroyed.",
          ),
          LoveApiArgumentDoc(
            name: "preSolve",
            type: "function",
            description: "Gets called before a collision gets resolved.",
            defaultValue: "nil",
          ),
          LoveApiArgumentDoc(
            name: "postSolve",
            type: "function",
            description: "Gets called after the collision has been resolved.",
            defaultValue: "nil",
          ),
        ],
        returns: <LoveApiReturnDoc>[],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/World:setCallbacks",
  ),
  LoveApiSymbolDoc(
    symbol: "World:setContactFilter",
    module: "love.physics",
    name: "setContactFilter",
    kind: "method",
    description:
        "Sets a function for collision filtering.\n\nIf the group and category filtering doesn't generate a collision decision, this function gets called with the two fixtures as arguments. The function should return a boolean value where true means the fixtures will collide and false means they will pass through each other.",
    container: "World",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "filter",
