  LoveApiSymbolDoc(
    symbol: "Channel:performAtomic",
    module: "love.thread",
    name: "performAtomic",
    kind: "method",
    description:
        "Executes the specified function atomically with respect to this Channel.\n\nCalling multiple methods in a row on the same Channel is often useful. However if multiple Threads are calling this Channel's methods at the same time, the different calls on each Thread might end up interleaved (e.g. one or more of the second thread's calls may happen in between the first thread's calls.)\n\nThis method avoids that issue by making sure the Thread calling the method has exclusive access to the Channel until the specified function has returned.",
    container: "Channel",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "func",
            type: "function",
            description:
                "The function to call, the form of function(channel, arg1, arg2, ...) end. The Channel is passed as the first argument to the function when it is called.",
          ),
          LoveApiArgumentDoc(
            name: "...",
            type: "any",
            description:
                "Additional arguments that the given function will receive when it is called.",
          ),
        ],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "ret1",
            type: "any",
            description:
                "The first return value of the given function (if any.)",
