  LoveApiSymbolDoc(
    symbol: "love.window.toPixels",
    module: "love.window",
    name: "toPixels",
    kind: "function",
    description:
        "Converts a number from density-independent units to pixels.\n\nThe pixel density inside the window might be greater (or smaller) than the 'size' of the window. For example on a retina screen in Mac OS X with the highdpi window flag enabled, the window may take up the same physical size as an 800x600 window, but the area inside the window uses 1600x1200 pixels. love.window.toPixels(800) would return 1600 in that case.\n\nThis is used to convert coordinates from the size users are expecting them to display at onscreen to pixels. love.window.fromPixels does the opposite. The highdpi window flag must be enabled to use the full pixel density of a Retina screen on Mac OS X and iOS. The flag currently does nothing on Windows and Linux, and on Android it is effectively always enabled.\n\nMost LÖVE functions return values and expect arguments in terms of pixels rather than density-independent units.",
    variants: <LoveApiVariantDoc>[
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "value",
            type: "number",
            description:
                "A number in density-independent units to convert to pixels.",
          ),
        ],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "pixelvalue",
            type: "number",
            description: "The converted number, in pixels.",
          ),
        ],
      ),
      LoveApiVariantDoc(
        arguments: <LoveApiArgumentDoc>[
          LoveApiArgumentDoc(
            name: "x",
            type: "number",
            description:
                "The x-axis value of a coordinate in density-independent units to convert to pixels.",
          ),
          LoveApiArgumentDoc(
            name: "y",
            type: "number",
            description:
                "The y-axis value of a coordinate in density-independent units to convert to pixels.",
          ),
        ],
        returns: <LoveApiReturnDoc>[
          LoveApiReturnDoc(
            name: "px",
            type: "number",
            description:
                "The converted x-axis value of the coordinate, in pixels.",
          ),
          LoveApiReturnDoc(
            name: "py",
            type: "number",
            description:
                "The converted y-axis value of the coordinate, in pixels.",
          ),
        ],
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/love.window.toPixels",
  ),
  LoveApiSymbolDoc(
    symbol: "love.window.updateMode",
    module: "love.window",
    name: "updateMode",
    kind: "function",
    description:
        "Sets the display mode and properties of the window, without modifying unspecified properties.\n\nIf width or height is 0, updateMode will use the width and height of the desktop.\n\nChanging the display mode may have side effects: for example, canvases will be cleared. Make sure to save the contents of canvases beforehand or re-draw to them afterward if you need to.",
