  LoveEnumDoc(
    symbol: "BlendAlphaMode",
    module: "love.graphics",
    name: "BlendAlphaMode",
    description:
        "Different ways alpha affects color blending. See BlendMode and the BlendMode Formulas for additional notes.",
    constants: <LoveEnumConstantDoc>[
      LoveEnumConstantDoc(
        name: "alphamultiply",
        description:
            "The RGB values of what's drawn are multiplied by the alpha values of those colors during blending. This is the default alpha mode.",
      ),
      LoveEnumConstantDoc(
        name: "premultiplied",
        description:
            "The RGB values of what's drawn are '''not''' multiplied by the alpha values of those colors during blending. For most blend modes to work correctly with this alpha mode, the colors of a drawn object need to have had their RGB values multiplied by their alpha values at some point previously (\"premultiplied alpha\").",
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/BlendAlphaMode",
  ),
  LoveEnumDoc(
    symbol: "BlendMode",
    module: "love.graphics",
    name: "BlendMode",
    description:
        "Different ways to do color blending. See BlendAlphaMode and the BlendMode Formulas for additional notes.",
    constants: <LoveEnumConstantDoc>[
      LoveEnumConstantDoc(
        name: "alpha",
        description:
            "Alpha blending (normal). The alpha of what's drawn determines its opacity.",
      ),
      LoveEnumConstantDoc(
        name: "replace",
        description:
            "The colors of what's drawn completely replace what was on the screen, with no additional blending. The BlendAlphaMode specified in love.graphics.setBlendMode still affects what happens.",
      ),
      LoveEnumConstantDoc(name: "screen", description: "'Screen' blending."),
      LoveEnumConstantDoc(
        name: "add",
        description:
            "The pixel colors of what's drawn are added to the pixel colors already on the screen. The alpha of the screen is not modified.",
      ),
      LoveEnumConstantDoc(
        name: "subtract",
        description:
            "The pixel colors of what's drawn are subtracted from the pixel colors already on the screen. The alpha of the screen is not modified.",
      ),
      LoveEnumConstantDoc(
        name: "multiply",
        description:
            "The pixel colors of what's drawn are multiplied with the pixel colors already on the screen (darkening them). The alpha of drawn objects is multiplied with the alpha of the screen rather than determining how much the colors on the screen are affected, even when the \"alphamultiply\" BlendAlphaMode is used.",
      ),
      LoveEnumConstantDoc(
        name: "lighten",
        description:
            "The pixel colors of what's drawn are compared to the existing pixel colors, and the larger of the two values for each color component is used. Only works when the \"premultiplied\" BlendAlphaMode is used in love.graphics.setBlendMode.",
      ),
      LoveEnumConstantDoc(
        name: "darken",
        description:
            "The pixel colors of what's drawn are compared to the existing pixel colors, and the smaller of the two values for each color component is used. Only works when the \"premultiplied\" BlendAlphaMode is used in love.graphics.setBlendMode.",
      ),
      LoveEnumConstantDoc(
        name: "additive",
        description: "Additive blend mode.",
      ),
      LoveEnumConstantDoc(
        name: "subtractive",
        description: "Subtractive blend mode.",
      ),
      LoveEnumConstantDoc(
        name: "multiplicative",
        description: "Multiply blend mode.",
      ),
      LoveEnumConstantDoc(
        name: "premultiplied",
        description: "Premultiplied alpha blend mode.",
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/BlendMode",
  ),
  LoveEnumDoc(
    symbol: "CompareMode",
    module: "love.graphics",
    name: "CompareMode",
    description:
        "Different types of per-pixel stencil test and depth test comparisons. The pixels of an object will be drawn if the comparison succeeds, for each pixel that the object touches.",
    constants: <LoveEnumConstantDoc>[
      LoveEnumConstantDoc(
        name: "equal",
        description:
            "* stencil tests: the stencil value of the pixel must be equal to the supplied value.\n* depth tests: the depth value of the drawn object at that pixel must be equal to the existing depth value of that pixel.",
      ),
      LoveEnumConstantDoc(
        name: "notequal",
        description:
            "* stencil tests: the stencil value of the pixel must not be equal to the supplied value.\n* depth tests: the depth value of the drawn object at that pixel must not be equal to the existing depth value of that pixel.",
      ),
      LoveEnumConstantDoc(
        name: "less",
        description:
            "* stencil tests: the stencil value of the pixel must be less than the supplied value.\n* depth tests: the depth value of the drawn object at that pixel must be less than the existing depth value of that pixel.",
      ),
      LoveEnumConstantDoc(
        name: "lequal",
        description:
            "* stencil tests: the stencil value of the pixel must be less than or equal to the supplied value.\n* depth tests: the depth value of the drawn object at that pixel must be less than or equal to the existing depth value of that pixel.",
      ),
      LoveEnumConstantDoc(
        name: "gequal",
        description:
            "* stencil tests: the stencil value of the pixel must be greater than or equal to the supplied value.\n* depth tests: the depth value of the drawn object at that pixel must be greater than or equal to the existing depth value of that pixel.",
      ),
      LoveEnumConstantDoc(
        name: "greater",
        description:
            "* stencil tests: the stencil value of the pixel must be greater than the supplied value.\n* depth tests: the depth value of the drawn object at that pixel must be greater than the existing depth value of that pixel.",
      ),
      LoveEnumConstantDoc(
        name: "never",
        description: "Objects will never be drawn.",
      ),
      LoveEnumConstantDoc(
        name: "always",
        description:
            "Objects will always be drawn. Effectively disables the depth or stencil test.",
      ),
    ],
    wikiPath: "https://www.love2d.org/wiki/CompareMode",
  ),
  LoveEnumDoc(
    symbol: "CullMode",
